external_knowledge:
- "Shining like stars" metaphorically refers to the active status of platforms; 
- "Brightness of their engagement" represents the total engagement value; 
- "First week" corresponds to `week_id` = 1.

sql:
SELECT SUM(likes) AS Total_Likes
FROM facebook_data
WHERE week_id = 1;

SELECT AVG(comments) AS average_comments
FROM instagram_data
WHERE week_date = '2022-01-01';

SELECT SUM(likes) AS TotalLikes, SUM(comments) AS TotalComments
FROM facebook_data
WHERE week_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT platform_name
FROM social_media_platforms
WHERE platform_id IN (SELECT platform_id FROM weekly_data);

SELECT week_date, tweets, replies, retweets
FROM twitter_data
ORDER BY week_date DESC;

SELECT COUNT(*) 
FROM client_access
WHERE access_date = '2023-05-01' AND access_type = 'view';

SELECT * 
FROM client_data 
WHERE industry = 'Finance' AND contact_person = 'John Doe';

SELECT week_date, SUM(emails_sent) AS total_emails_sent, SUM(emails_received) AS total_emails_received
FROM gmail_data
GROUP BY week_date;

SELECT week_id, emails_sent, emails_received
FROM gmail_data
WHERE week_date >= DATE('now', '-10 days');

